--
-- Table structure for table `db_product_src_detail`
--

DROP TABLE IF EXISTS `db_product_src_detail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `db_product_src_detail` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键，可以理解为任务ID',
  `gid` varchar(24) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '组ID',
  `product_title` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始商品标题',
  `product_url` varchar(2048) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始商品链接',
  `category_name` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始商品类目',
  `category_id` varchar(24) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原始商品类目ID',
  `spu_image_url` varchar(256) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '原始spu图片链接',
  `sku_image_url_list` text COLLATE utf8mb4_unicode_ci COMMENT '原始sku图片链接',
  `related_items` text COLLATE utf8mb4_unicode_ci COMMENT '原始相关项',
  `attributes` text COLLATE utf8mb4_unicode_ci COMMENT '原始商品属性',
  `supplier_name` varchar(256) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '供应商名称',
  `remark` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '描述',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `create_user` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'system' COMMENT '创建人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `update_user` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'system' COMMENT '修改人',
  PRIMARY KEY (`id`),
  KEY `idx_spd_gid` (`gid`),
  KEY `idx_spd_create_time` (`create_time`),
  KEY `idx_spd_update_time` (`update_time`),
  KEY `idx_spd_product_title` (`product_title`)
) ENGINE=InnoDB AUTO_INCREMENT=385 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='商品原始数据表';
/*!40101 SET character_set_client = @saved_cs_client */;

