  `notice_url` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '通知地址',
  `remark` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '描述',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `create_user` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'system' COMMENT '创建人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `update_user` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT 'system' COMMENT '修改人',
  PRIMARY KEY (`id`),
  KEY `idx_ptd_product_src_id` (`product_src_id`),
  KEY `idx_ptd_product_des_id` (`product_des_id`),
  KEY `idx_ptd_platform_id` (`platform_id`,`site`),
  KEY `idx_ptd_gid` (`gid`),
  KEY `idx_ptd_create_time` (`create_time`),
  KEY `idx_ptd_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=385 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='商品任务详情表';
