INSERT INTO `db_sys_ai_prompt` VALUES (1,'SYSTEM_TEXT_TRANSLATE','You are a translation expert. Translate text to specified language. Return only the translated text.',1,'翻译系统提示词','2026-03-27 14:55:42','system','2026-03-27 14:55:42','system'),(2,'USER_TEXT_TRANSLATE','Translate to %s: %s',1,'翻译用户提示词','2026-03-27 14:55:42','system','2026-03-27 14:55:42','system'),(3,'SYSTEM_BATCH_TEXT_TRANSLATE','You are a translation expert. Translate each item in the list to the specified language. Return ONLY a JSON array of translated strings, no other text.',1,'批量翻译系统提示词','2026-03-27 15:54:43','system','2026-03-27 15:54:43','system'),(4,'USER_BATCH_TEXT_TRANSLATE','Translate each item in the following list to %s: %s',1,'批量翻译用户提示词','2026-03-27 15:54:43','system','2026-03-27 15:54:43','system'),(5,'SYSTEM_IMAGE_OCR','You are an expert in image text recognition. Recognize and extract all text from the image. Return only the text content, no other explanation.',1,'OCR系统提示词','2026-03-27 16:57:06','system','2026-03-27 16:57:06','system'),(6,'USER_IMAGE_OCR','Please recognize all text in this image.',1,'OCR用户提示词','2026-03-27 16:57:06','system','2026-03-27 16:57:06','system'),(7,'SYSTEM_COMMON_CATEGORY_STEP_ONE','你是一个电商类目分析专家。根据商品图片和标题，分析商品类型并给出合适的类目路径。',1,'类目分析第一步系统提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(8,'USER_COMMON_CATEGORY_STEP_ONE','商品标题：%s\n原始类目：%s\n\n请根据图片和标题分析商品类型，给出最合适的类目路径。',1,'类目分析第一步用户提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(9,'SYSTEM_COMMON_CATEGORY_STEP_TWO','你是一个电商类目分析专家。从候选类目列表中选择最合适的类目。',1,'类目分析第二步系统提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(10,'USER_COMMON_CATEGORY_STEP_TWO','商品标题：%s\n候选类目列表：%s\n\n请从以上候选类目中选择最合适的类目。',1,'类目分析第二步用户提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(11,'SYSTEM_TIKTOKSHOP_PRODUCT_TITLE','你是一个TikTokShop商品标题优化专家。根据商品图片和信息，生成符合TikTokShop平台规范的优质商品标题。标题应该简洁、有吸引力，包含关键词。',1,'TikTokShop标题生成系统提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(12,'USER_TIKTOKSHOP_PRODUCT_TITLE','商品原标题：%s\n商品类目：%s\n目标语言：%s\n\n请根据图片和商品信息生成TikTokShop商品标题。',1,'TikTokShop标题生成用户提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(13,'SYSTEM_TIKTOKSHOP_PRODUCT_DESC','你是一个TikTokShop商品描述撰写专家。根据商品图片和信息，生成详细、吸引人的商品描述，突出产品特点和卖点。',1,'TikTokShop描述生成系统提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system'),(14,'USER_TIKTOKSHOP_PRODUCT_DESC','商品标题：%s\n商品类目：%s\n目标语言：%s\n\n请根据图片和商品信息生成TikTokShop商品描述。',1,'TikTokShop描述生成用户提示词','2026-04-06 17:32:24','system','2026-04-06 17:32:24','system');
